import{_ as a,C as r,o as s,c as o,E as i,a2 as d}from"./chunks/framework.C24VBsJ9.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"qa/qa_31.md","filePath":"qa/qa_31.md","lastUpdated":1781674711000}'),n={name:"qa/qa_31.md"};function l(p,t,h,c,k,u){const e=r("PageHeader");return s(),o("div",null,[i(e,{icon:"❓",title:"Issue #31: Docker 构建镜像更新相关疑问",description:"关于 Docker 环境构建和 SDK 版本的问答"}),t[0]||(t[0]=d('<p><strong>原文链接</strong>: <a href="https://github.com/Awesome-Embedded-Learning-Studio/imx-forge/issues/31" target="_blank" rel="noreferrer">GitHub Issue #31</a></p><blockquote><p>请注意Issue的时间和时效性！如果存在行为变化，但是本文档没有反馈Update行为，欢迎Issue我们！我们会持续收录可能会对其他朋友有所帮助的Issue!</p></blockquote><hr><h2 id="q1-docker-compose-命令失败" tabindex="-1">Q1: docker compose 命令失败 <a class="header-anchor" href="#q1-docker-compose-命令失败" aria-label="Permalink to &quot;Q1: docker compose 命令失败&quot;">​</a></h2><p><strong>问题</strong>：尝试使用 <code>docker compose up -d --build</code> 构建环境时出现错误。</p><p><strong>解答</strong>：本项目未配置 docker compose，不支持该命令。请使用以下命令构建：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DOCKER_BUILDKIT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> imx-forge:latest</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="q2-docker-buildkit-1-会完全重建镜像吗" tabindex="-1">Q2: DOCKER_BUILDKIT=1 会完全重建镜像吗？ <a class="header-anchor" href="#q2-docker-buildkit-1-会完全重建镜像吗" aria-label="Permalink to &quot;Q2: DOCKER_BUILDKIT=1 会完全重建镜像吗？&quot;">​</a></h2><p><strong>问题</strong>：每次运行 <code>DOCKER_BUILDKIT=1 docker build</code> 都会完全重新构建整个镜像吗？</p><p><strong>解答</strong>：不会。<code>DOCKER_BUILDKIT=1</code> 启用的是新版 BuildKit 构建系统，支持增量构建和缓存机制，不会每次都完全重建镜像。只有在 Dockerfile 或源文件发生变化时才会重新构建相关层。</p><hr><h2 id="q3-编译器下载非常慢" tabindex="-1">Q3: 编译器下载非常慢 <a class="header-anchor" href="#q3-编译器下载非常慢" aria-label="Permalink to &quot;Q3: 编译器下载非常慢&quot;">​</a></h2><p><strong>问题</strong>：第一次构建和重新构建镜像时都会卡在编译器下载步骤，下载速度很慢。</p><p><strong>解答</strong>：这通常是网络问题导致。可能的原因：</p><ul><li>编译器服务器在国内访问不稳定</li><li>需要使用代理加速下载</li></ul><p><strong>已经改进</strong></p><ol><li>移除 Dockerfile 中的 <code>wget -q</code> 参数，显示详细下载信息，提升可调试性(目前已经做到，如果您发现)</li></ol><p><strong>计划改进</strong>：</p><ol><li>预构建 Docker 镜像并上传到 Docker Hub，用户可以直接拉取现成镜像开始开发。目前还是托管到Github的，如果的确存在需求，提出Issue让我们知道，并且为您的需求进行开发！</li></ol><hr><h2 id="q4-docker-镜像和官方-sdk-的区别是什么" tabindex="-1">Q4: Docker 镜像和官方 SDK 的区别是什么？ <a class="header-anchor" href="#q4-docker-镜像和官方-sdk-的区别是什么" aria-label="Permalink to &quot;Q4: Docker 镜像和官方 SDK 的区别是什么？&quot;">​</a></h2><p><strong>问题</strong>：本项目的 Docker 镜像与开发板厂商（如正点原子）提供的 SDK 有什么区别？</p><p><strong>解答</strong>：以下是正点原子官方 SDK 与 imx-forge 的版本对比：</p><table tabindex="0"><thead><tr><th>组件</th><th>正点原子</th><th>imx-forge</th></tr></thead><tbody><tr><td>U-Boot</td><td>2016</td><td>2025</td></tr><tr><td>内核</td><td>4.1.15</td><td>6.12.49 / 7.1</td></tr><tr><td>BusyBox</td><td>1.32</td><td>1.37</td></tr><tr><td>编译器 (GCC)</td><td>Linaro GCC 8.x</td><td>GCC 15.2.1</td></tr><tr><td>Qt</td><td>Qt 5.12</td><td>Qt 6.9</td></tr></tbody></table><p>imx-forge 使用更新的软件版本，提供更现代的开发环境。</p><hr><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="/imx-forge/tutorial/docker/">Docker 环境搭建教程</a></li><li><a href="/imx-forge/QUICK_START">快速开始指南</a></li></ul>',29))])}const m=a(n,[["render",l]]);export{b as __pageData,m as default};
